import pdfplumber, sys, json

files = [
    'CMDKT.pdf', 'CMKT.pdf', 'FINER.pdf', 'GKT.pdf',
    'KeenKT.pdf', 'PLKT.pdf', 'TBKT.pdf', 'UKT.pdf'
]
base = r'C:\Users\vokhn\Documents\OpenScience\2026-07-08-0908\sources'

results = {}
for f in files:
    path = f'{base}\\{f}'
    try:
        with pdfplumber.open(path) as pdf:
            text = ''
            for i, page in enumerate(pdf.pages):
                if i < 4:  # first 4 pages enough for abstract/intro
                    t = page.extract_text()
                    if t:
                        text += t + '\n\n'
            results[f] = text[:3000]
    except Exception as e:
        results[f] = f'ERROR: {e}'

for k, v in results.items():
    print(f'===== {k} =====')
    print(v)
    print()
"
